module shift_register(clk, load, data_in, shift_en, data_out);
  input clk;
  input load;
  input [15:0] data_in;
  input shift_en;
  output [15:0] data_out;

  reg [15:0] shadow_reg;

  always @(posedge clk) begin
    if (load) begin
      shadow_reg <= data_in;
    end else if (shift_en) begin
      shadow_reg <= {shadow_reg[14:0], 1'b0};
    end
  end

  assign data_out = shadow_reg;

endmodule
